  1 import Foundation
  2 
  3 /// Discovers child components of an incident.io status-page group.
  4 ///
  5 /// incident.io exposes no public unauthenticated JSON endpoint for the
  6 /// component hierarchy, so we parse the Next.js RSC payload embedded in the
  7 /// page HTML. The payload arrives as `self.__next_f.push([1, "..."])` calls
  8 /// whose second argument is a JSON-escaped chunk; concatenating those chunks
  9 /// (and unescaping `\"`) yields a stream that contains plain
 10 /// `"id":"...","name":"...","group_id":"..."` objects we can mine with a
 11 /// regex.
 12 ///
 13 /// Fails loud (throws) if the page yields zero matches — the page schema may
 14 /// have changed and we want the test suite (or the manual refresh button) to
 15 /// surface that immediately rather than silently masking it with an empty
 16 /// list.
 17 public protocol IncidentIOComponentsDiscovery: Sendable {
 18     func discover(host: String, groupRootID: StatusComponentID) async throws -> [StatusComponent]
 19 }
 20 
 21 public enum IncidentIOComponentsDiscoveryError: Error, CustomStringConvertible {
 22     case invalidURL(rawValue: String)
 23     case networkError(underlying: Error, url: String)
 24     case unexpectedResponse(statusCode: Int, url: String)
 25     case noComponentsFound(url: String, groupRootID: String)
 26 
 27     public var description: String {
 28         switch self {
 29         case let .invalidURL(raw):
 30             "Invalid status page URL: \(raw)"
 31         case let .networkError(err, url):
 32             "Status page network error for \(url): \(err)"
 33         case let .unexpectedResponse(code, url):
 34             "Status page returned HTTP \(code) for \(url)"
 35         case let .noComponentsFound(url, groupRootID):
 36             "No incident.io components matched group_id=\(groupRootID) on \(url) — page schema may have changed"
 37         }
 38     }
 39 }
 40 
 41 public actor IncidentIOPageComponentsDiscovery: IncidentIOComponentsDiscovery {
 42     private let logger: FileLogger
 43     private let session: URLSession
 44     private let requestTimeoutSeconds: TimeInterval
 45 
 46     public init(
 47         logger: FileLogger = Loggers.codex,
 48         session: URLSession = .shared,
 49         requestTimeoutSeconds: TimeInterval = 10.0
 50     ) {
 51         self.logger = logger
 52         self.session = session
 53         self.requestTimeoutSeconds = requestTimeoutSeconds
 54     }
 55 
 56     public func discover(
 57         host: String,
 58         groupRootID: StatusComponentID
 59     ) async throws -> [StatusComponent] {
 60         let urlString = "https://\(host)/"
 61         guard let url = URL(string: urlString) else {
 62             throw IncidentIOComponentsDiscoveryError.invalidURL(rawValue: urlString)
 63         }
 64         var request = URLRequest(url: url)
 65         request.timeoutInterval = requestTimeoutSeconds
 66         request.setValue("text/html", forHTTPHeaderField: "Accept")
 67 
 68         logger.log(.debug, "Discovering incident.io components from \(urlString)")
 69 
 70         let data: Data
 71         let response: URLResponse
 72         do {
 73             (data, response) = try await session.data(for: request)
 74         } catch {
 75             throw IncidentIOComponentsDiscoveryError.networkError(underlying: error, url: urlString)
 76         }
 77 
 78         let httpCode = (response as? HTTPURLResponse)?.statusCode ?? -1
 79         guard httpCode == 200 else {
 80             throw IncidentIOComponentsDiscoveryError.unexpectedResponse(
 81                 statusCode: httpCode, url: urlString
 82             )
 83         }
 84 
 85         let html = String(decoding: data, as: UTF8.self)
 86         let components = Self.extractComponents(fromHTML: html, groupRootID: groupRootID)
 87 
 88         guard !components.isEmpty else {
 89             throw IncidentIOComponentsDiscoveryError.noComponentsFound(
 90                 url: urlString,
 91                 groupRootID: groupRootID.rawValue
 92             )
 93         }
 94 
 95         logger.log(
 96             .info,
 97             "Discovered \(components.count) incident.io component(s) under group \(groupRootID.rawValue)"
 98         )
 99         return components
100     }
101 
102     /// Public for tests: extracts components from a raw page HTML string by
103     /// matching the JSON-shaped triples embedded in the Next.js RSC payload.
104     public static func extractComponents(
105         fromHTML html: String,
106         groupRootID: StatusComponentID
107     ) -> [StatusComponent] {
108         // RSC chunks live inside JS string literals where every `"` is escaped
109         // as `\"`. Unescape once so a single regex covers both the rare
110         // unescaped occurrences and the normal escaped ones.
111         let unescaped = html.replacingOccurrences(of: "\\\"", with: "\"")
112         return extractComponents(fromUnescapedPayload: unescaped, groupRootID: groupRootID)
113     }
114 
115     /// Same as `extractComponents(fromHTML:)` but takes a payload whose JSON
116     /// string-escaping has already been undone — useful for tests that hand in
117     /// a plain JSON fixture rather than a full HTML page.
118     public static func extractComponents(
119         fromUnescapedPayload payload: String,
120         groupRootID: StatusComponentID
121     ) -> [StatusComponent] {
122         // Strategy: incident.io serializes a group's children as a nested
123         // `components` array on the group object itself, e.g.
124         // `{"components":[{"component_id":"01...","name":"Codex Web",…},…],
125         //   …,"id":"<group_root_id>","name":"Codex"}`.
126         // So we:
127         //   1. locate the enclosing object that carries `"id":"<groupRootID>"`,
128         //   2. find its `"components":[…]` array,
129         //   3. enumerate each top-level child object inside that array.
130         //
131         // No depth-aware string tracking is needed — after unescape, value
132         // strings never contain a literal `{` or `}` in the incident.io
133         // shape we're targeting.
134         guard let groupObject = enclosingObject(
135             containing: "\"id\":\"\(groupRootID.rawValue)\"",
136             in: payload
137         ) else { return [] }
138         guard let componentsArray = extractArray(named: "components", in: groupObject) else {
139             return []
140         }
141         var seenIDs = Set<String>()
142         var components: [StatusComponent] = []
143         for slice in enumerateTopLevelObjects(in: componentsArray) {
144             guard let id = firstCapture(
145                 in: slice,
146                 pattern: #"\"component_id\"\s*:\s*\"([0-9A-HJKMNP-TV-Z]{26})\""#
147             ) else { continue }
148             guard let name = firstCapture(
149                 in: slice,
150                 pattern: #"\"name\"\s*:\s*\"([^\"\\]{1,200})\""#
151             ) else { continue }
152             guard seenIDs.insert(id).inserted else { continue }
153             components.append(StatusComponent(
154                 id: StatusComponentID(rawValue: id),
155                 name: name,
156                 groupID: groupRootID
157             ))
158         }
159         return components
160     }
161 
162     /// Returns the smallest `{…}` substring that wholly contains `needle`,
163     /// walking outward from the needle's first occurrence and matching
164     /// braces. `nil` if no such enclosure exists.
165     private static func enclosingObject(containing needle: String, in payload: String) -> String? {
166         guard let needleRange = payload.range(of: needle) else { return nil }
167 
168         var depth = 0
169         var openIndex: String.Index?
170         var index = payload.index(before: needleRange.lowerBound)
171         while index >= payload.startIndex {
172             let ch = payload[index]
173             if ch == "}" {
174                 depth += 1
175             } else if ch == "{" {
176                 if depth == 0 {
177                     openIndex = index
178                     break
179                 }
180                 depth -= 1
181             }
182             if index == payload.startIndex { break }
183             index = payload.index(before: index)
184         }
185         guard let openIndex else { return nil }
186 
187         depth = 0
188         var forward = needleRange.upperBound
189         while forward < payload.endIndex {
190             let ch = payload[forward]
191             if ch == "{" {
192                 depth += 1
193             } else if ch == "}" {
194                 if depth == 0 {
195                     let endExclusive = payload.index(after: forward)
196                     return String(payload[openIndex..<endExclusive])
197                 }
198                 depth -= 1
199             }
200             forward = payload.index(after: forward)
201         }
202         return nil
203     }
204 
205     /// Extracts the substring inside `"<name>":[ … ]` (the brackets included).
206     private static func extractArray(named field: String, in text: String) -> String? {
207         guard let opening = text.range(of: "\"\(field)\":[")
208             ?? text.range(of: "\"\(field)\": [")
209         else { return nil }
210         var depth = 0
211         var index = text.index(before: opening.upperBound)
212         while index < text.endIndex {
213             let ch = text[index]
214             if ch == "[" {
215                 depth += 1
216             } else if ch == "]" {
217                 depth -= 1
218                 if depth == 0 {
219                     let endExclusive = text.index(after: index)
220                     return String(text[opening.upperBound..<endExclusive])
221                 }
222             }
223             index = text.index(after: index)
224         }
225         return nil
226     }
227 
228     private static func enumerateTopLevelObjects(in payload: String) -> [String] {
229         // The component objects we mine are flat — values never contain
230         // `{` or `}` — so plain brace depth counting is sufficient.
231         var depth = 0
232         var sliceStart: String.Index?
233         var slices: [String] = []
234         var index = payload.startIndex
235         while index < payload.endIndex {
236             let ch = payload[index]
237             if ch == "{" {
238                 if depth == 0 {
239                     sliceStart = index
240                 }
241                 depth += 1
242             } else if ch == "}" {
243                 if depth > 0 {
244                     depth -= 1
245                     if depth == 0, let start = sliceStart {
246                         let endInclusive = payload.index(after: index)
247                         slices.append(String(payload[start..<endInclusive]))
248                         sliceStart = nil
249                     }
250                 }
251             }
252             index = payload.index(after: index)
253         }
254         return slices
255     }
256 
257     private static func firstCapture(in text: String, pattern: String) -> String? {
258         guard let regex = try? NSRegularExpression(pattern: pattern, options: []) else {
259             return nil
260         }
261         let ns = text as NSString
262         let range = NSRange(location: 0, length: ns.length)
263         guard let match = regex.firstMatch(in: text, options: [], range: range),
264               match.numberOfRanges == 2 else { return nil }
265         return ns.substring(with: match.range(at: 1))
266     }
267 }

