  1 import Foundation
  2 
  3 // MARK: - StatusPlatform
  4 
  5 /// The status-page platform a vendor uses. Open-ended so future vendors using
  6 /// statuspage.io / etc can reuse the same registry + preferences shell.
  7 public struct StatusPlatform: RawRepresentable, Codable, Equatable, Hashable, Sendable {
  8     public let rawValue: String
  9     public init(rawValue: String) { self.rawValue = rawValue }
 10 
 11     public static let incidentIO = StatusPlatform(rawValue: "incidentIO")
 12 
 13     public init(from decoder: Decoder) throws {
 14         rawValue = try decoder.singleValueContainer().decode(String.self)
 15     }
 16 
 17     public func encode(to encoder: Encoder) throws {
 18         var container = encoder.singleValueContainer()
 19         try container.encode(rawValue)
 20     }
 21 }
 22 
 23 extension StatusPlatform: ExpressibleByStringLiteral {
 24     public init(stringLiteral value: String) { rawValue = value }
 25 }
 26 
 27 extension StatusPlatform: CustomStringConvertible {
 28     public var description: String { rawValue }
 29 }
 30 
 31 // MARK: - StatusComponentID
 32 
 33 /// Stable per-component ULID assigned by the status-page platform. Used as
 34 /// the subscription key — names like "App" or "CLI" are not unique across
 35 /// groups so they cannot serve as keys.
 36 public struct StatusComponentID: RawRepresentable, Codable, Equatable, Hashable, Sendable {
 37     public let rawValue: String
 38     public init(rawValue: String) { self.rawValue = rawValue }
 39 
 40     public init(from decoder: Decoder) throws {
 41         rawValue = try decoder.singleValueContainer().decode(String.self)
 42     }
 43 
 44     public func encode(to encoder: Encoder) throws {
 45         var container = encoder.singleValueContainer()
 46         try container.encode(rawValue)
 47     }
 48 }
 49 
 50 extension StatusComponentID: ExpressibleByStringLiteral {
 51     public init(stringLiteral value: String) { rawValue = value }
 52 }
 53 
 54 extension StatusComponentID: CustomStringConvertible {
 55     public var description: String { rawValue }
 56 }
 57 
 58 // MARK: - StatusComponent
 59 
 60 /// A single child component of a status-page group (e.g. "Codex Web" under
 61 /// the "Codex" group). The id is the subscription key; `name` is shown to
 62 /// users in the preferences UI so the listing is meaningful instead of a
 63 /// raw ULID.
 64 public struct StatusComponent: Codable, Equatable, Hashable, Sendable, Identifiable {
 65     public let id: StatusComponentID
 66     public let name: String
 67     public let groupID: StatusComponentID
 68 
 69     public init(id: StatusComponentID, name: String, groupID: StatusComponentID) {
 70         self.id = id
 71         self.name = name
 72         self.groupID = groupID
 73     }
 74 
 75     private enum CodingKeys: String, CodingKey {
 76         case id
 77         case name
 78         case groupID = "group_id"
 79     }
 80 }
 81 
 82 // MARK: - StatusComponentsCacheEntry
 83 
 84 /// One refresh result for a (platform, host, group-root) triple. Indexing by
 85 /// all three keeps the file open to future vendors on the same platform
 86 /// without collisions.
 87 public struct StatusComponentsCacheEntry: Codable, Equatable, Sendable {
 88     public let platform: StatusPlatform
 89     public let host: String
 90     public let groupRootID: StatusComponentID
 91     public var lastRefreshedAt: ISODate
 92     public var components: [StatusComponent]
 93 
 94     public init(
 95         platform: StatusPlatform,
 96         host: String,
 97         groupRootID: StatusComponentID,
 98         lastRefreshedAt: ISODate,
 99         components: [StatusComponent]
100     ) {
101         self.platform = platform
102         self.host = host
103         self.groupRootID = groupRootID
104         self.lastRefreshedAt = lastRefreshedAt
105         self.components = components
106     }
107 
108     private enum CodingKeys: String, CodingKey {
109         case platform
110         case host
111         case groupRootID = "group_root_id"
112         case lastRefreshedAt = "last_refreshed_at"
113         case components
114     }
115 }
116 
117 // MARK: - StatusComponentsCache
118 
119 /// Root document for `status-components.json`.
120 public struct StatusComponentsCache: Codable, Equatable, Sendable {
121     public var entries: [StatusComponentsCacheEntry]
122 
123     public init(entries: [StatusComponentsCacheEntry] = []) {
124         self.entries = entries
125     }
126 
127     public func entry(
128         platform: StatusPlatform,
129         host: String,
130         groupRootID: StatusComponentID
131     ) -> StatusComponentsCacheEntry? {
132         entries.first {
133             $0.platform == platform
134                 && $0.host == host
135                 && $0.groupRootID == groupRootID
136         }
137     }
138 
139     public mutating func upsert(_ entry: StatusComponentsCacheEntry) {
140         if let idx = entries.firstIndex(where: {
141             $0.platform == entry.platform
142                 && $0.host == entry.host
