  1 import Foundation
  2 import Darwin
  3 
  4 /// Persists `StatusComponentsCache` to a JSON file alongside the usages
  5 /// cache. Uses a dedicated lock file so atomic writes (which replace the
  6 /// inode) do not invalidate flock-based reader synchronization.
  7 public actor StatusComponentsFileManager {
  8     public static let shared = StatusComponentsFileManager()
  9 
 10     nonisolated public let filePath: String
 11     nonisolated public let lockPath: String
 12     private let logger: FileLogger
 13     private let lockTimeoutSeconds: TimeInterval
 14 
 15     init(
 16         filePath: String? = nil,
 17         logger: FileLogger = Loggers.app,
 18         lockTimeoutSeconds: TimeInterval = 5.0
 19     ) {
 20         let home = FileManager.default.homeDirectoryForCurrentUser.path
 21         self.filePath = filePath ?? "\(home)/.cache/ai-usages-tracker/status-components.json"
 22         self.logger = logger
 23         self.lockPath = self.filePath + ".lock"
 24         self.lockTimeoutSeconds = lockTimeoutSeconds
 25 
 26         let dir = (self.filePath as NSString).deletingLastPathComponent
 27         do {
 28             try FileManager.default.createDirectory(
 29                 atPath: dir, withIntermediateDirectories: true, attributes: nil
 30             )
 31         } catch {
 32             logger.log(.error, "Failed to create status-components cache directory \(dir): \(error)")
 33         }
 34     }
 35 
 36     public func read() async -> StatusComponentsCache {
 37         do {
 38             return try await withFileLock(mode: LOCK_SH) { readUnsafe() }
 39         } catch is CancellationError {
 40             return StatusComponentsCache()
 41         } catch {
 42             logger.log(.warning, "flock read failed on status-components — returning empty: \(error)")
 43             return StatusComponentsCache()
 44         }
 45     }
 46 
 47     public func upsert(_ entry: StatusComponentsCacheEntry) async {
 48         do {
 49             try await withFileLock(mode: LOCK_EX) {
 50                 var cache = readUnsafe()
 51                 cache.upsert(entry)
 52                 writeUnsafe(cache)
 53             }
 54         } catch is CancellationError {
 55             return
 56         } catch {
 57             logger.log(.warning, "flock upsert failed on status-components: \(error)")
 58         }
 59     }
 60 
 61     private func withFileLock<T>(mode: Int32, body: () throws -> T) async throws -> T {
 62         let fd = Darwin.open(lockPath, O_CREAT | O_RDWR, 0o644)
 63         guard fd >= 0 else { throw FileManagerError.cannotOpenLockFile(path: lockPath) }
 64         defer { Darwin.close(fd) }
 65 
 66         let deadline = Date().addingTimeInterval(lockTimeoutSeconds)
 67         while flock(fd, mode | LOCK_NB) != 0 {
 68             guard Date() < deadline else {
 69                 throw FileManagerError.lockTimeout(path: lockPath, timeoutSeconds: lockTimeoutSeconds)
 70             }
 71             try await Task.sleep(for: .milliseconds(50))
 72         }
 73         defer { flock(fd, LOCK_UN) }
 74 
 75         return try body()
 76     }
 77 
 78     private func readUnsafe() -> StatusComponentsCache {
 79         guard let data = FileManager.default.contents(atPath: filePath) else {
 80             return StatusComponentsCache()
 81         }
 82         do {
 83             return try JSONDecoder().decode(StatusComponentsCache.self, from: data)
 84         } catch {
 85             logger.log(.error, "Failed to decode \(filePath): \(error)")
 86             return StatusComponentsCache()
 87         }
 88     }
 89 
 90     private func writeUnsafe(_ cache: StatusComponentsCache) {
 91         let encoder = JSONEncoder()
 92         encoder.outputFormatting = [.prettyPrinted, .sortedKeys]
 93         guard let data = try? encoder.encode(cache) else {
 94             logger.log(.error, "Failed to encode status-components cache")
 95             return
 96         }
 97         do {
 98             try data.write(to: URL(fileURLWithPath: filePath), options: .atomic)
 99         } catch {
100             logger.log(.error, "Atomic write failed on status-components: \(error)")
101             return
102         }
103         logger.log(.debug, "Wrote status-components cache to \(filePath)")
104     }
105 }

