  4 struct StatusSettingsView: View {
  5     let preferences: any AppPreferences
  6     let registry: StatusComponentRegistry
  7 
  8     @State private var components: [StatusComponent] = []
  9     @State private var lastRefreshedAt: ISODate?
 10     @State private var isRefreshing = false
 11     @State private var refreshError: String?
 12 
 13     var body: some View {
 14         let concretePrefs = AppDelegate.sharedPreferences
 15         Form {
 16             Section("Codex components") {
 17                 Text("Codex outage banners only surface when an incident affects at least one subscribed component.")
 18                     .font(.caption)
 19                     .foregroundStyle(.secondary)
 20 
 21                 if components.isEmpty {
 22                     Text("No components discovered yet. Click \"Refresh now\" to fetch the current list from status.openai.com.")
 23                         .foregroundStyle(.secondary)
 24                 } else {
 25                     ForEach(components) { component in
 26                         Toggle(isOn: subscriptionBinding(for: component, in: concretePrefs)) {
 27                             VStack(alignment: .leading, spacing: 2) {
 28                                 Text(component.name)
 29                                     .font(.system(size: 13))
 30                                 Text(component.id.rawValue)
 31                                     .font(.system(size: 10, design: .monospaced))
 32                                     .foregroundStyle(.secondary)
 33                             }
 34                         }
 35                     }
 36                 }
 37             }
 38 
 39             Section("Refresh") {
 40                 HStack {
 41                     if let lastRefreshedAt {
 42                         Text("Last refreshed: \(lastRefreshedAt.rawValue)")
 43                             .font(.caption)
 44                             .foregroundStyle(.secondary)
 45                     } else {
 46                         Text("Last refreshed: never")
 47                             .font(.caption)
 48                             .foregroundStyle(.secondary)
 49                     }
 50                     Spacer()
 51                     Button("Refresh now") {
 52                         Task { await performRefresh() }
 53                     }
 54                     .disabled(isRefreshing)
 55                 }
 56 
 57                 if let refreshError {
 58                     Text(refreshError)
 59                         .font(.caption)
 60                         .foregroundStyle(.red)
 61                 }
 62             }
 63         }
 64         .formStyle(.grouped)
 65         .task { await loadCached() }
 66     }
 67 
 68     private func subscriptionBinding(
 69         for component: StatusComponent,
 70         in prefs: UserDefaultsAppPreferences
 71     ) -> Binding<Bool> {
 72         Binding(
 73             get: { prefs.statusComponentSubscriptions[component.id.rawValue] ?? true },
 74             set: { newValue in
 75                 var current = prefs.statusComponentSubscriptions
 76                 if newValue {
 77                     current.removeValue(forKey: component.id.rawValue)
 78                 } else {
 79                     current[component.id.rawValue] = false
 80                 }
 81                 prefs.statusComponentSubscriptions = current
 82             }
 83         )
 84     }
 85 
 86     private func loadCached() async {
 87         guard let entry = await registry.cachedEntry() else { return }
 88         self.components = entry.components
 89         self.lastRefreshedAt = entry.lastRefreshedAt
 90     }
 91 
 92     private func performRefresh() async {
 93         isRefreshing = true
 94         refreshError = nil
 95         defer { isRefreshing = false }
 96         do {
 97             let entry = try await registry.refresh()
 98             self.components = entry.components
 99             self.lastRefreshedAt = entry.lastRefreshedAt
100         } catch {
101             refreshError = String(describing: error)
102         }
103     }
104 }

